// Monta um item por conta social ativa + agenda publishTime em slots fixos
const clip = $('fetch-clip-do-nicho').item.json;
const rawAccounts = Array.isArray($json.publishAccounts)
  ? $json.publishAccounts
  : Array.isArray($json.data?.publishAccounts)
    ? $json.data.publishAccounts
    : Array.isArray($json.data)
      ? $json.data
      : Array.isArray($json.accounts)
        ? $json.accounts
        : [];
const activeAccounts = rawAccounts.filter(a => String(a?.status || '').toLowerCase() === 'active' || Number(a?.status) === 1);

if (activeAccounts.length === 0) {
  return [];
}

const SLOT_HOURS = [8, 14, 20]; // manha, tarde, noite (America/Sao_Paulo)
const LEAD_SECONDS = 120; // evita agendar no passado imediato

// Converte "agora" para data/hora SP (BRT fixo -03)
function getSpNowParts() {
  const now = new Date();
  const utcMs = now.getTime() + now.getTimezoneOffset() * 60000;
  const sp = new Date(utcMs - 3 * 60 * 60 * 1000);
  return {
    year: sp.getUTCFullYear(),
    month: sp.getUTCMonth() + 1,
    day: sp.getUTCDate(),
  };
}

function spToEpoch(year, month, day, hour) {
  // Hora SP para epoch UTC (SP = UTC-3)
  return Math.floor(Date.UTC(year, month - 1, day, hour + 3, 0, 0) / 1000);
}

function addDays(year, month, day, daysToAdd) {
  const d = new Date(Date.UTC(year, month - 1, day + daysToAdd));
  return {
    year: d.getUTCFullYear(),
    month: d.getUTCMonth() + 1,
    day: d.getUTCDate(),
  };
}

function getFirstAvailableSlot(nowUnix) {
  const spNow = getSpNowParts();

  for (let i = 0; i < SLOT_HOURS.length; i += 1) {
    const candidate = spToEpoch(spNow.year, spNow.month, spNow.day, SLOT_HOURS[i]);
    if (candidate > nowUnix + LEAD_SECONDS) {
      return {
        baseYear: spNow.year,
        baseMonth: spNow.month,
        baseDay: spNow.day,
        baseSlotIndex: i,
      };
    }
  }

  const nextDay = addDays(spNow.year, spNow.month, spNow.day, 1);
  return {
    baseYear: nextDay.year,
    baseMonth: nextDay.month,
    baseDay: nextDay.day,
    baseSlotIndex: 0,
  };
}

function getSlotEpochFromBase(base, offsetSlots) {
  const total = base.baseSlotIndex + offsetSlots;
  const dayOffset = Math.floor(total / SLOT_HOURS.length);
  const slotIndex = total % SLOT_HOURS.length;
  const targetDate = addDays(base.baseYear, base.baseMonth, base.baseDay, dayOffset);
  return spToEpoch(targetDate.year, targetDate.month, targetDate.day, SLOT_HOURS[slotIndex]);
}

const sd = $getWorkflowStaticData('global');
const nowUnix = Math.floor(Date.now() / 1000);
const runKey = String(($('schedule-3x-dia').item.json.timestamp || Date.now()));

if (sd.schedulerRunKey !== runKey) {
  sd.schedulerRunKey = runKey;
  sd.schedulerBase = getFirstAvailableSlot(nowUnix);
  sd.schedulerOffset = 0;
}

// Um slot por clip (todas as contas desse clip usam o mesmo horario)
const clipOffset = Number(sd.schedulerOffset || 0);
const publishTime = getSlotEpochFromBase(sd.schedulerBase, clipOffset);
sd.schedulerOffset = clipOffset + 1;

return activeAccounts.map(account => ({
  json: {
    clip_id:          clip.clip_id,
    vizard_video_id:  clip.vizard_video_id,
    titulo_final:     clip.titulo_final || '',
    descricao_final:  clip.descricao_final || '',
    descricao_base:   clip.descricao_base || '',
    hashtags:         clip.hashtags || '',
    nicho:            clip.nicho || '',
    canal_id:         clip.canal_id || '',
    score_clip:       clip.score_clip || 0,
    arquivo_clip_url: clip.arquivo_clip_url || '',

    // Dados da conta social
    account_id:       String(account.id || account.socialAccountId || ''),
    account_platform: String(account.platform || account.type || account.socialPlatform || 'unknown').toLowerCase(),
    account_name:     account.username || account.page || account.name || '',
    has_account:      true,

    // Agendamento (Unix int64)
    publish_time:     publishTime,
  }
}));

// Avalia resultado da publicacao (imediata x agendada)
const payload = $('loop-by-account').item.json;
const result = $input.first().json;
const isSuccess = Number(result.code) === 2000;

const nowUnix = Math.floor(Date.now() / 1000);
const scheduledUnix = Number(payload.publish_time || 0);
const isScheduled = isSuccess && scheduledUnix > nowUnix + 60;

return [{
  json: {
    ...payload,
    publish_success:  isSuccess,
    publish_code:     result.code ?? null,
    publish_error:    isSuccess ? null : JSON.stringify(result).substring(0, 500),
    pub_status:       isSuccess ? (isScheduled ? 'agendado' : 'publicado') : 'erro',
    pub_platform_id:  isSuccess ? (result.data?.id || result.data?.videoId || null) : null,
    pub_scheduled_for: isScheduled ? scheduledUnix : null,
  }
}];

// HTTP error path — marca como erro
const payload = $('loop-by-account').item.json;
const result = $input.first().json;

return [{
  json: {
    ...payload,
    publish_success: false,
    publish_code:    null,
    publish_error:   JSON.stringify(result).substring(0, 500),
    pub_status:      'erro',
    pub_platform_id: null
  }
}];

